    // Constraints: 1 <= nums[i] <= 10^5. Max value V = 10^5.
    val MAX_VAL = 100000

    // 1. Create a boolean array/set to quickly check if a number is in the original set D.
    // We use an array since the maximum value is small (10^5).
    val isInD = BooleanArray(MAX_VAL + 1) { false }

    for (x in nums) {
        // Since x <= 10^5, we cast it safely to Int for array indexing.
        if (x <= MAX_VAL) {
            isInD[x.toInt()] = true
        }
    }

    var totalSum: Long = 0

    // 2. Iterate through each element x in the original array nums.
    for (x_long in nums) {
        val x = x_long.toInt()

        // Find the smallest divisor d of x such that d is present in the original set D.
        var min_d_star = x // Initialize with x itself (x is always a divisor of x, and x is in D)

        // Iterate through divisors up to sqrt(x)
        var i = 1
        while (i * i <= x) {
            if (x % i == 0) {
                val d1 = i
                val d2 = x / i

                // Check d1
                if (isInD[d1]) {
                    // Since we are iterating i upwards, d1 is increasing, so the first one found is the smallest.
                    // However, we must check both i and x/i against the current min_d_star.
                    min_d_star = Math.min(min_d_star, d1)
                }

                // Check d2
                if (isInD[d2]) {
                    min_d_star = Math.min(min_d_star, d2)
                }
            }
            i++
        }

        // Add the smallest possible value for this element to the total sum
        totalSum += min_d_star.toLong()
    }

    return totalSum
}

