fun solve(nums: Array<Long>): Long {
    // Maximum possible value based on constraints
    val V_MAX = 100000

    // counts[i] stores the frequency of value i in nums.
    // We use IntArray because values are <= 10^5.
    val counts = IntArray(V_MAX + 1) { 0 }
    var currentMax = 0

    // Step 1: Count frequencies and find the maximum value present
    for (num in nums) {
        val n = num.toInt()
        if (n <= V_MAX) {
            counts[n]++
            if (n > currentMax) {
                currentMax = n
            }
        }
        // Constraint guarantees n <= V_MAX
    }

    // R[i] will store the smallest value r present in nums such that r divides i.
    // Initialize R[i] = i. This handles cases where i has no smaller divisor present in nums.
    // We only need to initialize up to currentMax.
    val R = IntArray(currentMax + 1) { it }

    // Step 2: Sieve process to find the minimum divisor for every unique element
    // We iterate through potential divisors r from 1 up to currentMax.
    for (r in 1..currentMax) {
        // If r is present in the original array (r is in U)
        if (counts[r] > 0) {
            // Check all multiples x = k*r that are also present in the original array (x is in U)
            var x = 2 * r
            while (x <= currentMax) {
                if (counts[x] > 0) {
                    // Since we iterate r in increasing order, r is guaranteed to be the smallest
                    // divisor in U found so far for x.
                    R[x] = r
                }
                x += r
            }
        }
    }

    // Step 3: Calculate the total minimum sum
    var totalSum: Long = 0
    for (i in 1..currentMax) {
        if (counts[i] > 0) {
            // Original value i appears counts[i] times.
            // It reduces to R[i].
            totalSum += counts[i].toLong() * R[i].toLong()
        }
    }

    return totalSum
